head.b:skin:
/* ============================================= */
/* IRAN POLITICAL NEWS - PREMIUM DARK THEME v2   */
/* ============================================= */

:root {
  --primary: #c0392b;
  --primary-dark: #a93226;
  --primary-glow: rgba(192, 57, 43, 0.15);
  --accent: #e74c3c;
  --bg-dark: #0d0d0d;
  --bg-card: #151515;
  --bg-card-hover: #1a1a1a;
  --text-main: #ecf0f1;
  --text-muted: #8e99a4;
  --border: #1e2a35;
  --border-light: #2a3a4a;
  --header-bg: #060606;
  --glass: rgba(255,255,255,0.03);
  --shadow-sm: 0 2px 8px rgba(0,0,0,0.3);
  --shadow-md: 0 8px 25px rgba(0,0,0,0.4);
  --shadow-lg: 0 15px 40px rgba(0,0,0,0.5);
  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 14px;
  --transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

/* --- RESET & BASE --- */
* { box-sizing: border-box; outline: none; }
body {
  margin: 0; padding: 0;
  font-family: 'Vazir', sans-serif;
  background-color: var(--bg-dark);
  color: var(--text-main);
  direction: rtl;
  font-size: 14px;
  line-height: 1.8;
  -webkit-font-smoothing: antialiased;
}
a { text-decoration: none; color: inherit; transition: var(--transition); }
a:hover { color: var(--primary); }
img { max-width: 100%; height: auto; display: block; }
ul { list-style: none; padding: 0; margin: 0; }

/* --- TOP ALERT BAR (BREAKING NEWS) --- */
.alert-bar {
  background: linear-gradient(135deg, var(--primary) 0%, #8e1a0e 100%);
  color: #fff;
  font-size: 12px;
  padding: 10px 0;
  display: flex;
  align-items: center;
  box-shadow: 0 2px 10px rgba(192, 57, 43, 0.3);
}
.alert-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 15px;
  display: flex;
  width: 100%;
}
.alert-title {
  background: rgba(0,0,0,0.4);
  padding: 3px 14px;
  border-radius: 20px;
  font-weight: 900;
  margin-left: 15px;
  white-space: nowrap;
  text-transform: uppercase;
  font-size: 11px;
  letter-spacing: 1px;
  backdrop-filter: blur(5px);
}
.alert-marquee { flex: 1; font-weight: bold; }

/* --- HEADER --- */
.site-header {
  background: var(--header-bg);
  padding: 25px 0;
  border-bottom: 1px solid var(--border);
  position: relative;
}
.site-header::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--primary), transparent);
  opacity: 0.4;
}
.header-content {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 15px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.logo-text h1 {
  font-size: 32px;
  font-weight: 900;
  letter-spacing: -1px;
  margin: 0;
}
.logo-text span { color: var(--primary); }
.header-date { color: var(--text-muted); font-size: 12px; }

/* Language Switcher */
.lang-switcher {
  display: flex;
  gap: 8px;
}
.lang-btn {
  display: flex;
  align-items: center;
  gap: 5px;
  background: var(--glass);
  border: 1px solid var(--border);
  padding: 7px 14px;
  border-radius: 25px;
  font-size: 11px;
  color: var(--text-muted);
  transition: var(--transition);
  backdrop-filter: blur(5px);
}
.lang-btn:hover {
  background: var(--primary);
  color: #fff;
  border-color: var(--primary);
  transform: translateY(-1px);
  box-shadow: 0 4px 12px rgba(192, 57, 43, 0.3);
}
.lang-btn img {
  width: 18px;
  height: 12px;
  border-radius: 2px;
}

/* --- NAVIGATION --- */
.main-nav {
  background: rgba(15, 15, 15, 0.95);
  border-bottom: 1px solid var(--border);
  position: sticky; top: 0; z-index: 999;
  backdrop-filter: blur(10px);
}
.nav-inner {
  max-width: 1200px; margin: 0 auto; padding: 0 15px;
  display: flex; height: 50px; align-items: center;
}
.nav-links { display: flex; gap: 25px; height: 100%; }
.nav-links a {
  display: flex; align-items: center; height: 100%;
  font-weight: 700; font-size: 13px; color: #bbb;
  border-top: 3px solid transparent;
  transition: var(--transition);
  position: relative;
}
.nav-links a:hover { color: #fff; border-top-color: var(--primary); }
.nav-links a::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 50%;
  right: 50%;
  height: 2px;
  background: var(--primary);
  transition: var(--transition);
  opacity: 0;
}
.nav-links a:hover::after {
  left: 0;
  right: 0;
  opacity: 1;
}
.nav-search { margin-right: auto; }
.nav-search input {
  background: rgba(255,255,255,0.05); border: 1px solid var(--border); color: #fff;
  padding: 7px 16px; border-radius: 25px 0 0 25px; font-family: inherit; font-size: 12px;
  width: 160px; transition: var(--transition);
}
.nav-search input:focus {
  background: rgba(255,255,255,0.08);
  border-color: var(--primary);
  width: 200px;
}
.search-btn {
  background: var(--primary);
  border: none;
  color: #fff;
  padding: 7px 14px;
  border-radius: 0 25px 25px 0;
  cursor: pointer;
  transition: var(--transition);
}
.search-btn:hover { background: var(--primary-dark); transform: scale(1.05); }

/* --- MAIN LAYOUT --- */
.main-container {
  max-width: 1200px; margin: 40px auto; padding: 0 15px;
  display: grid; grid-template-columns: 800px 1fr; gap: 40px;
}

/* --- FEATURED SECTION (First Post) --- */
.hero-post {
  position: relative;
  margin-bottom: 40px;
  border-radius: var(--radius-lg);
  overflow: hidden;
  box-shadow: var(--shadow-lg);
}
.hero-thumb {
  width: 100%; height: 450px; object-fit: cover;
  filter: brightness(0.65);
  transition: 0.6s cubic-bezier(0.4, 0, 0.2, 1);
}
.hero-post:hover .hero-thumb { filter: brightness(0.85) scale(1.03); }
.hero-content {
  position: absolute; bottom: 0; right: 0; left: 0;
  padding: 50px 40px 40px;
  background: linear-gradient(to top, rgba(0,0,0,0.95) 0%, rgba(0,0,0,0.5) 50%, transparent 100%);
}
.hero-cat {
  background: var(--primary); color: #fff;
  padding: 5px 14px; font-size: 10px; font-weight: bold;
  border-radius: 20px; text-transform: uppercase;
  margin-bottom: 12px; display: inline-block;
  letter-spacing: 1px;
  box-shadow: 0 2px 8px rgba(192, 57, 43, 0.4);
}
.hero-title {
  font-size: 34px; font-weight: 900; color: #fff;
  margin: 10px 0; line-height: 1.35;
  text-shadow: 0 2px 8px rgba(0,0,0,0.6);
}
.hero-meta { color: rgba(255,255,255,0.7); font-size: 12px; }

/* --- HOMEPAGE LAYOUT --- */
.homepage-loop {
  display: flex;
  flex-wrap: wrap;
  gap: 20px;
}
.hero-post, .news-grid-title {
  width: 100%;
}
.post-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-md); overflow: hidden;
  display: flex; flex-direction: column;
  transition: var(--transition);
  width: calc(50% - 10px);
  position: relative;
}
.post-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: linear-gradient(90deg, var(--primary), var(--accent));
  opacity: 0;
  transition: var(--transition);
  z-index: 1;
}
.post-card:hover {
  border-color: var(--border-light);
  transform: translateY(-4px);
  box-shadow: var(--shadow-md);
  background: var(--bg-card-hover);
}
.post-card:hover::before { opacity: 1; }
.card-thumb { height: 190px; overflow: hidden; position: relative; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; transition: 0.5s cubic-bezier(0.4, 0, 0.2, 1); }
.post-card:hover .card-thumb img { transform: scale(1.08); }
.card-body { padding: 22px; flex: 1; display: flex; flex-direction: column; }
.card-title { font-size: 15px; font-weight: 800; margin-bottom: 10px; line-height: 1.6; height: 48px; overflow: hidden; }
.card-excerpt { font-size: 13px; color: var(--text-muted); height: 55px; overflow: hidden; margin-bottom: 15px; line-height: 1.7; flex: 1; }
.card-link {
  font-size: 11px; font-weight: bold; color: var(--primary);
  display: inline-flex; align-items: center; gap: 4px;
  transition: var(--transition);
}
.card-link:hover { gap: 8px; }

/* --- SIDEBAR WIDGETS --- */
.widget-box {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  padding: 25px;
  margin-bottom: 30px;
  transition: var(--transition);
}
.widget-box:hover {
  border-color: var(--border-light);
  box-shadow: var(--shadow-sm);
}
.widget-header {
  font-size: 14px; font-weight: 900;
  color: #fff; text-transform: uppercase;
  border-bottom: 2px solid var(--primary);
  padding-bottom: 12px; margin-bottom: 20px;
  letter-spacing: 1.5px;
  position: relative;
}
.widget-header::after {
  content: '';
  position: absolute;
  bottom: -2px;
  right: 0;
  width: 40px;
  height: 2px;
  background: var(--accent);
}

/* Statistics Widget */
.stat-card {
  background: linear-gradient(135deg, rgba(255,255,255,0.03), rgba(255,255,255,0.01));
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 18px;
  margin-bottom: 12px;
  display: flex;
  align-items: center;
  gap: 15px;
  transition: var(--transition);
}
.stat-card:hover {
  border-color: var(--primary);
  background: var(--primary-glow);
}
.stat-icon {
  font-size: 24px;
  width: 45px;
  height: 45px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  background: var(--primary-glow);
  color: var(--primary);
}
.stat-info { flex: 1; text-align: left; }
.stat-label { font-size: 12px; color: var(--text-muted); margin-bottom: 2px; }
.stat-val { font-size: 28px; font-weight: 900; color: #fff; font-family: 'Vazir', sans-serif; }
.stat-update { font-size: 11px; color: var(--text-muted); margin-top: 8px; }

/* Quote Widget */
.quote-box { text-align: center; }
.quote-img {
  width: 85px; height: 85px; border-radius: 50%; object-fit: cover;
  margin: 0 auto 15px;
  border: 3px solid var(--primary);
  box-shadow: 0 0 20px rgba(192, 57, 43, 0.2);
  transition: var(--transition);
}
.quote-box:hover .quote-img { transform: scale(1.05); box-shadow: 0 0 30px rgba(192, 57, 43, 0.3); }
.quote-text {
  font-style: italic; font-size: 14px; color: #ccc;
  margin-bottom: 15px; line-height: 1.7;
  position: relative;
  padding: 0 10px;
}
.quote-text::before {
  content: '\201C';
  font-size: 50px;
  color: var(--primary);
  opacity: 0.3;
  position: absolute;
  top: -15px;
  right: -5px;
  font-family: Georgia, serif;
}
.quote-author { font-weight: bold; color: #fff; font-size: 12px; }

/* Bank Links */
.bank-link {
  display: block;
  padding: 12px 16px;
  margin-bottom: 10px;
  color: #fff;
  text-decoration: none;
  border-radius: var(--radius-sm);
  font-size: 13px;
  font-weight: bold;
  text-align: center;
  transition: var(--transition);
  position: relative;
  overflow: hidden;
}
.bank-link::before {
  content: '';
  position: absolute;
  top: 0; left: -100%;
  width: 100%; height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.1), transparent);
  transition: 0.5s;
}
.bank-link:hover::before { left: 100%; }
.bank-link:hover { transform: translateY(-2px); box-shadow: var(--shadow-sm); color: #fff; }
.bank-link-blue { background: linear-gradient(135deg, #1a237e, #1565c0); }
.bank-link-green { background: linear-gradient(135deg, #1b5e20, #2e7d32); }

/* Footer */
.main-footer {
  background: #050505; border-top: 1px solid var(--border);
  padding: 60px 0 30px; margin-top: 60px;
  position: relative;
}
.main-footer::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--primary), transparent);
  opacity: 0.3;
}
.footer-inner { max-width: 1200px; margin: 0 auto; padding: 0 15px; display: grid; grid-template-columns: repeat(4, 1fr); gap: 40px; }
.footer-col h4 { 
  color: #fff; border-bottom: 2px solid var(--primary); 
  display: inline-block; padding-bottom: 8px; margin-bottom: 20px;
  font-size: 14px; letter-spacing: 1px;
}
.footer-col ul li {
  margin-bottom: 10px; border-bottom: 1px solid rgba(255,255,255,0.05);
  padding-bottom: 8px; transition: var(--transition);
}
.footer-col ul li:hover { padding-right: 8px; }
.footer-col ul li a { color: var(--text-muted); font-size: 13px; }
.footer-col ul li a:hover { color: var(--primary); }
.footer-copyright {
  text-align: center; margin-top: 40px; color: #444;
  font-size: 11px; border-top: 1px solid rgba(255,255,255,0.05);
  padding-top: 20px;
}

/* Hide Blogger's default pager */
.blog-pager { display: none !important; }

/* Custom Numbered Pagination */
#numbered-pagination {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 8px;
  margin: 40px auto;
  padding: 20px 0;
  flex-wrap: wrap;
}
.page-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 42px;
  height: 42px;
  padding: 0 14px;
  background: var(--bg-card);
  color: var(--text-main);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  font-size: 14px;
  font-weight: 600;
  font-family: 'Vazir', sans-serif;
  cursor: pointer;
  transition: var(--transition);
  text-decoration: none;
}
.page-btn:hover {
  background: var(--primary);
  color: #fff;
  border-color: var(--primary);
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(192, 57, 43, 0.3);
}
.page-btn.active {
  background: linear-gradient(135deg, var(--primary), var(--accent));
  color: #fff;
  border-color: var(--primary);
  box-shadow: 0 4px 15px rgba(192, 57, 43, 0.4);
  pointer-events: none;
}
.page-btn.dots {
  background: transparent;
  border: none;
  pointer-events: none;
  color: var(--text-muted);
  min-width: 30px;
}
.page-info {
  display: block;
  text-align: center;
  margin-bottom: 15px;
  color: var(--text-muted);
  font-size: 12px;
}

/* --- RESPONSIVE --- */
@media (max-width: 1000px) {
  .main-container { display: flex; flex-direction: column; }
  .hero-title { font-size: 22px; }
  .hero-thumb { height: 300px; }
  .hero-content { padding: 30px 20px 20px; }
  .post-card { width: 100%; }
  .footer-inner { grid-template-columns: 1fr; text-align: center; }
  .nav-search input { width: 120px; }
}

/* Smooth scroll */
html { scroll-behavior: smooth; }

/* Selection color */
::selection {
  background: var(--primary);
  color: #fff;
}

/* Scrollbar */
::-webkit-scrollbar { width: 8px; }
::-webkit-scrollbar-track { background: var(--bg-dark); }
::-webkit-scrollbar-thumb { background: #333; border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: var(--primary); }

body.script:
//
  // === ADVANCED DEDUPLICATION and TICKER SYSTEM ===
  document.addEventListener('DOMContentLoaded', function() {

     // 1. Advanced Duplicate Removal (Hero vs Grid)
     function removeDuplicates() {
         var heroLink = document.querySelector('.hero-post a');
         if (!heroLink) return;
         var heroUrl = heroLink.href;
         var gridCards = document.querySelectorAll('.post-card');
         gridCards.forEach(function(card) {
             var cardLink = card.querySelector('a');
             if (cardLink && cardLink.href === heroUrl) {
                 card.remove();
             }
         });
     }
     removeDuplicates();

     // 2. Live News Ticker (Iran Intl)
     var rssUrl = 'https://www.iranintl.com/fa/rss';
     var timestamp = new Date().getTime();
     var proxyUrl = 'https://corsproxy.io/?' + encodeURIComponent(rssUrl) + '&_t=' + timestamp;

     fetch(proxyUrl)
      .then(function(res) { 
          if (!res.ok) throw new Error("Network response was not ok");
          return res.text(); 
      })
      .then(function(str) {
          var parser = new DOMParser();
          var xml = parser.parseFromString(str, "text/xml");
          var items = xml.getElementsByTagName("item");
          var headlines = [];
          for(var i=0; i < Math.min(items.length, 10); i++) {
              var t = items[i].getElementsByTagName("title")[0];
              if(t) headlines.push(t.textContent);
          }
          if(headlines.length > 0) {
             var ticker = document.getElementById('live-ticker');
             if(ticker) ticker.innerHTML = headlines.join(' \u2022 ');
          } else {
             throw new Error("No news items found");
          }
      })
      .catch(function(e) {
          console.error('Ticker Error:', e);
          var ticker = document.getElementById('live-ticker');
          if(ticker) ticker.innerHTML = "\u067e\u0648\u0634\u0634 \u0644\u062d\u0638\u0647\u200c\u0627\u06cc \u0645\u0647\u0645\u200c\u062a\u0631\u06cc\u0646 \u0627\u062e\u0628\u0627\u0631 \u0627\u06cc\u0631\u0627\u0646 \u0648 \u062c\u0647\u0627\u0646";
      });
  });
//

//
  (function() {
    document.cookie = 'googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;';
    document.cookie = 'googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/; domain=.blogspot.com;';
    document.cookie = 'googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/; domain=' + location.hostname + ';';
  })();

  function googleTranslateElementInit() {
    new google.translate.TranslateElement({
      pageLanguage: 'fa',
      includedLanguages: 'en,de',
      autoDisplay: false
    }, 'google_translate_element');
  }

  function translateTo(lang) {
    if (lang === 'fa') {
      document.cookie = 'googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;';
      document.cookie = 'googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/; domain=.blogspot.com;';
      document.cookie = 'googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/; domain=' + location.hostname + ';';
      location.reload();
      return;
    }
    var select = document.querySelector('.goog-te-combo');
    if (select) {
      select.value = lang;
      select.dispatchEvent(new Event('change'));
    } else {
      setTimeout(function() {
        var s = document.querySelector('.goog-te-combo');
        if (s) { s.value = lang; s.dispatchEvent(new Event('change')); }
      }, 1000);
    }
  }
//
